import React from "react";
import { useNavigate } from "react-router-dom";
import "./Section.css";

function Pathology({ fullPage }) {
  const navigate = useNavigate();

  if (fullPage) {
    return (
      <div className="full-page">
        <h2>Pathology Services</h2>
        <p>Detailed info about pathology labs and booking services.</p>
      </div>
    );
  }

  return (
    <div className="section-card" onClick={() => navigate("/pathology")}>
      <div className="icon">🔬</div>
      <h3>Pathology Services</h3>
      <p>Find and book appointments with leading pathology labs for accurate diagnostics.</p>
    </div>
  );
}

export default Pathology;
